sql:
SELECT request_key_value
FROM request_keys
WHERE method = 'POST' AND is_active = 1;

SELECT COUNT(*) AS active_post_requests
  FROM request_keys
  WHERE method = 'POST' AND is_active = 1;

SELECT token_value
FROM authentication_tokens
WHERE token_type = 'OAuth 2.0' AND is_active = 1;

SELECT COUNT(*) AS active_token_count
FROM authentication_tokens
WHERE is_active = 1 AND expiration_date > DATE('now');

SELECT header_name
FROM http_request_headers
WHERE required = 1;

SELECT MIN(expiration_date) 
FROM authentication_tokens 
WHERE is_active = 1;

external_knowledge:
Active requests: Requests with is_active = 1; 
Active HTTP request headers: Headers with is_active = 1; 
Method-override headers: Headers with method_override = 1; 
Active authentication tokens: Tokens with is_active = 1 and expiration_date > CURRENT_DATE; 
Most recent request key for each request: The request key with the highest creation time for each request ID.

